  ('IntexGlobal','BMTD02','Rubber Bar Mat Sublimated Bar Accessory','rubber-bar-mat-sublimated-bar-accessory-bmtd02','Barware','Bar Accessories','The Rubber Bar Mat is a high-quality, functional, and fully customizable bar accessory, ideal for bars, restaurants, events, and promotional branding. Designed to protect countertops and enhance brand visibility, this bar mat is made to order, with custom size options and branding capabilities.',1,true,false,'["Available in Square or Round Shape: Choose the perfect shape to match your branding needs.", "Laminated Top: Provides a smooth, durable surface for added longevity.", "Lightweight & Disposable: Ideal for high-volume use at events, bars, and restaurants.", "Absorbent & Functional: Protects surfaces from moisture and drink condensation.", "Customizable Branding Area: Can be sublimation printed with logos or promotional designs."]'::jsonb,'[{"name": "Size", "value": "85 (w) x 25 (h) cm"}]'::jsonb,'[{"name": "Custom", "hex": "", "image": ""}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/rubber-bar-mat-sublimated/');
