  ('IntexGlobal','COLB01','Perisher Cooler Bag','perisher-cooler-bag-colb01','Bags','Cooler Bags','The Perisher Cooler Bag is a practical and durable promotional item, designed to keep food and beverages fresh while providing excellent branding opportunities. Ideal for picnics, outdoor events, and corporate giveaways.',250,true,false,'["Large Insulated Interior: Lined with EVA material for superior temperature retention.", "Durable 80gsm Non-Woven Exterior: Lightweight yet sturdy for everyday use.", "Zip Closure: Ensures secure storage and helps maintain insulation.", "Spacious Design: Perfect for carrying food, drinks, and snacks for outdoor activities.", "Eco-Friendly & Reusable: A sustainable alternative to disposable coolers.", "Large Branding Area: Ideal for printing logos, slogans, or promotional designs."]'::jsonb,'[{"name": "Size", "value": "31 (w) x 32 (h) x 21 (d) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-orange.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb01/colb01-royal.webp"}]'::jsonb,null,'supplier',true,true,1.89,28,'indent_sea','Intex','https://www.intexglobal.com/product/perisher-cooler-bag/');
