  ('IntexGlobal','COLB03','Smiggins Cooler Bag','smiggins-cooler-bag-colb03','Bags','Cooler Bags','The Smiggins Cooler Bag is a lightweight and practical 6-can cooler, perfect for keeping drinks and snacks fresh while on the go. Its compact design and adjustable strap make it ideal for outdoor events, corporate promotions, and giveaways.',250,true,false,'["Durable 210D Nylon Material: Strong yet lightweight for everyday use.", "Holds Up to 6 Cans: Perfect for carrying beverages, snacks, or small meals.", "Adjustable Webbed Carry Strap: Ensures comfortable and easy transportation.", "Secure Zip Closure: Helps maintain insulation and freshness.", "Available in Multiple Colours: Choose from a variety of fabric shades to match your brand.", "Large Branding Area: Ideal for printing logos, event names, or promotional messages."]'::jsonb,'[{"name": "Size", "value": "21 (w) x 20 (h) x 16 (d) cm"}]'::jsonb,'[{"name": "Burgundy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-burgundy.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/colb03/colb03-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w4