  ('IntexGlobal','EYE01','Eye Mask Travel Accessory','eye-mask-travel-accessory-eye01','Travel','Travel Accessories','The Eye Mask is a lightweight and comfortable sleep accessory, designed to block out light and promote better sleep. Made from soft polyester material with an elastic strap, it provides a secure yet gentle fit, making it ideal for travel, relaxation, and corporate giveaways.',250,true,false,'["Soft Polyester Material: Ensures comfort during sleep or rest.", "Elastic Strap: Provides a secure and adjustable fit.", "Blocks Out Light: Helps improve sleep quality in any environment.", "Lightweight & Travel-Friendly: Perfect for flights, road trips, and relaxation.", "Ideal for Home & Travel Use: Great for hotels, spas, and corporate wellness programs.", "Custom Branding Available: Can be printed with logos for promotional use."]'::jsonb,'[{"name": "Size", "value": "18 (w) x 8 (h) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/eye01/eye01-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/eye01/eye01-blue.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/eye01/eye01-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/eye01/eye01-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/eye01/eye01-white.webp"}]'::jsonb,null,'supplier',true,true,0.42,28,'indent_sea','Intex','https://www.intexglobal.com/product/eye-mask/');
