  ('IntexGlobal','FAN001','Foldable Fan Supporter Gear','foldable-fan-supporter-gear-fan001','Outdoor & Lifestyle','Supporter Gear','The Foldable Bamboo Fan is a classic and stylish accessory, perfect for cooling off in warm weather while showcasing natural craftsmanship. Made from durable bamboo, this lightweight and foldable fan is ideal for outdoor events, promotional giveaways, and corporate branding.',250,true,false,'["Classic Bamboo Construction: Sturdy, eco-friendly, and elegantly designed.", "Foldable & Portable: Easily fits into bags and pockets for convenient carrying.", "Lightweight & Durable: Provides a refreshing breeze with a simple flick.", "Timeless & Stylish Design: Perfect for casual and formal occasions."]'::jsonb,'[{"name": "Size", "value": "23 (w) x 30 (h) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/fan001/fan001-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/fan001/fan001-green.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/fan001/fan001-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/fan001/fan001-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/fan001/fan001-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/fan001/fan001-yellow.webp"}]'::jsonb,null,'supplier',true,true,1.16,28,'indent_sea','Intex','https://www.intexglobal.com/product/foldable-fan/');
