  ('IntexGlobal','FOLB05','Adelaide Shopping Bag With Gusset','adelaide-shopping-bag-with-gusset-folb05','Bags','Tote Bags','The Adelaide Shopping Bag with Gusset is a lightweight, foldable, and reusable shopping bag, designed for convenience and sustainability. Made from durable 190T nylon, it easily folds into a clip-on pouch, making it perfect for on-the-go shopping and promotional giveaways.',250,true,false,'["Durable 190T Nylon Material: Strong, lightweight, and built for everyday use.", "Foldable Design: Conveniently folds into a compact clip-on pouch, making storage easy.", "Gusseted Base: Expands to provide extra space for groceries and other essentials.", "Clip Attachment: Easily clips onto bags, keys, or belts for portability.", "Large Branding Area: Ideal for screen printing logos, slogans, or promotional designs.", "Versatile Use: Perfect for shopping, corporate giveaways, trade shows, and retail promotions."]'::jsonb,'[{"name": "Size", "value": "30 x 35 cm"}]'::jsonb,'[{"name": "Black", "hex": "#000000", "image": ""}, {"name": "Royal", "hex": "#0033A0", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}, {"name": "Orange", "hex": "#FF6900", "image": ""}, {"name": "Yellow", "hex": "#FFD700", "image": ""}, {"name": "Green", "hex": "#009639", "image": ""}, {"name": "Lime Green", "hex": "#A5CD39", "image": ""}]'::jsonb,null,'supplier',true,true,1.77,28,'indent_sea','Intex','https://www.intexglobal.com/product/adelaide-shopping-bag-with-gusset/');
