  ('IntexGlobal','JUTB23','Jute Shopping Bag','jute-shopping-bag-jutb23','Bags','Jute Bags','The Jute Shopping Bag is a sustainable and reusable tote, perfect for shopping, corporate giveaways, and promotional branding. Made from natural hessian jute, this bag combines strength, durability, and eco-conscious appeal while offering a comfortable carrying experience with wider natural cotton handles.',250,true,false,'["Premium Natural Hessian Jute: Strong, biodegradable, and environmentally friendly.", "Wider Natural Cotton Handles: Soft and sturdy for comfortable carrying.", "Spacious Design: Ideal for groceries, retail, or daily essentials.", "Durable & Reusable: Designed to carry heavier loads while reducing plastic waste.", "Large Branding Area: Perfect for printing logos, slogans, or promotional messages."]'::jsonb,'[{"name": "Size", "value": "32(w) x 40(h) x 10(g) cm"}]'::jsonb,'[{"name": "Natural", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/jutb23/jutb23-main.webp"}]'::jsonb,null,'supplier',true,true,2.84,28,'indent_sea','Intex','https://www.intexglobal.com/product/jute-shopping-bag/');
