  ('IntexGlobal','LANY14a','Dog Lead Pet Accessory','dog-lead-pet-accessory-lany14a','Pet','Pet Accessories','Introducing the Dog Lead—Strong, Comfortable, and Built for Everyday Walks. Designed for durability and ease of use, this flat ribbed dog leash features a heavy-duty swivel hook for secure attachment and smooth movement. It''s the perfect choice for daily walks, ensuring both comfort for your dog and control for you.',250,true,false,'["Made with flat ribbed webbing for strength and long-lasting use.", "Heavy-duty swivel hook prevents tangling and ensures secure leash attachment.", "Comfortable to hold, offering a firm grip for the handler.", "Ideal for daily walks, training, or outdoor adventures.", "Suitable for dogs of various sizes and breeds."]'::jsonb,'[{"name": "Size", "value": "150cm x 2cm"}]'::jsonb,'[{"name": "Black", "hex": "#000000", "image": ""}, {"name": "White", "hex": "#FFFFFF", "image": ""}, {"name": "Yellow", "hex": "#FFD700", "image": ""}, {"name": "Orange", "hex": "#FF6900", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}, {"name": "Maroon", "hex": "#800000", "image": ""}, {"name": "Royal Blue", "hex": "#0033A0", "image": ""}, {"name": "Navy Blue", "hex": "#001F3F", "image": ""}, {"name": "Purple", "hex": "#5F259F", "image": ""}, {"name": "Green", "hex": "#009639", "image": ""}, {"name": "Pink", "hex": "#E45DBF", "image": ""}]'::jsonb,null,'supplier',true,true,2.58,28,'indent_sea','Intex','https://www.intexglobal.com/product/lany14a/');
