  ('IntexGlobal','LIFE32','Sweat Band With Zipper Sport Product','sweat-band-with-zipper-sport-product-life32','Outdoor & Lifestyle','Sports Products','The Sweat Band with Zipper is a versatile and practical accessory, designed for sports, workouts, and outdoor activities. Made from soft cotton with spandex, it offers excellent sweat absorption while featuring a hidden zippered pocket, perfect for storing small essentials like keys, cash, or coins during exercise.',1,true,false,'["Soft & Stretchable Cotton Fabric: Ensures a comfortable and secure fit.", "Sweat Absorbent: Helps keep sweat away from the hands and wrists.", "Built-in Zippered Pocket: Provides convenient storage for small valuables.", "Elastic Edge for a Snug Fit: Stays in place during high-intensity activities.", "Lightweight & Comfortable: Ideal for extended wear during sports and workouts.", "Custom Branding Available: Can be printed or embroidered with logos for promotional use."]'::jsonb,'[{"name": "Size", "value": "8cm(w) x 8cm(h)"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/life32/life32-black.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/life32/life32-grey.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/life32/life32-orange.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/life32/life32-pink.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/life32/life32-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/life32/life32-red.webp"}, {"name": "Royal Blue",