  ('IntexGlobal','MEKR03','Bradford Aluminium Bottle Opener Keyring','bradford-aluminium-bottle-opener-keyring-mekr03','Key Rings','Novelty Keyrings','The Bradford Aluminium Bottle Opener Keyring is a sleek and functional accessory, designed for convenience and portability. Made from lightweight yet durable aluminium, this compact opener is a practical promotional giveaway that ensures your brand stays in the hands of customers daily.',250,true,false,'["Durable Aluminium Construction: Lightweight and strong for long-lasting use.", "Compact & Portable Design: Easily attaches to keychains, bags, or lanyards.", "Multi-Functional: Works as both a keyring and a bottle opener.", "Smooth & Stylish Finish: Adds a sleek look to the design.", "Perfect for On-the-Go Use: Ideal for bars, events, picnics, and outdoor activities."]'::jsonb,'[{"name": "Size", "value": "7 (w) x 1 (h) cm"}]'::jsonb,'[{"name": "Blue", "hex": "#0057B8", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}, {"name": "Black", "hex": "#000000", "image": ""}, {"name": "Green", "hex": "#009639", "image": ""}, {"name": "White", "hex": "#FFFFFF", "image": ""}, {"name": "Yellow", "hex": "#FFD700", "image": ""}]'::jsonb,null,'supplier',true,true,1.03,28,'indent_sea','Intex','https://www.intexglobal.com/product/bradford-aluminium-bottle-opener-keyring/');
