  ('IntexGlobal','NWTB30','Blueys Tote Bag','blueys-tote-bag-nwtb30','Bags','Tote Bags','The Blueys Tote Bag is a practical and eco-friendly promotional product, designed to securely carry multiple takeaway coffee cups while offering excellent branding opportunities.',250,true,false,'["Durable 80gsm Non-Woven Material: Lightweight yet strong enough for repeated use.", "Holds Up to 4 Cups: Designed to securely transport multiple takeaway coffee cups.", "Customizable Surface: Ideal for branding with logos, slogans, or promotional designs.", "Eco-Friendly & Reusable: A sustainable alternative to disposable carriers, perfect for businesses promoting sustainability.", "Convenient & Practical: Ideal for cafés, catering services, corporate giveaways, and coffee runs."]'::jsonb,'[{"name": "Size", "value": "18 (w) x 14 (h) x 18 (d)cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb30/nwtb30-black.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb30/nwtb30-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb30/nwtb30-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb30/nwtb30-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb30/nwtb30-royal.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb30/nwtb30-navy.webp"}]'::jsonb,null,'supplier',true,true,0.63,28,'indent_sea','Intex','https://www.intexglobal.com/product/blueys-tote-bag/');
