  ('IntexGlobal','NWTB3391','Heat Sealed Non-Woven Exhibition Tote Tote Bag','heat-sealed-non-woven-exhibition-tote-tote-bag-nwtb3391','Bags','Tote Bags','The Heat Sealed Non-Woven Exhibition Tote is the perfect budget-friendly promotional bag, ideal for conferences, trade shows, and events. Its lightweight design and large branding area make it a great choice for high-visibility marketing.',250,true,false,'["Durable 80gsm Non-Woven Material: Lightweight yet sturdy construction for everyday use.", "Die Cut Handle: Comfortable and easy to carry, enhancing convenience.", "Heat-Sealed Design: Provides a sleek, seamless finish for added durability.", "Eco-Friendly & Reusable: A sustainable alternative to plastic bags, promoting environmental responsibility.", "Large Custom Branding Area: Ideal for showcasing logos, event details, or promotional messages.", "Inexpensive & Effective: A cost-effective marketing tool for high-volume giveaways."]'::jsonb,'[{"name": "Size", "value": "28 (w) x 36 (h) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb3391/nwtb3391-black.webp"}, {"name": "Bottle Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb3391/nwtb3391-bottle-green.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb3391/nwtb3391-green.webp"}, {"name": "Hot Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb3391/nwtb3391-hot-pink.webp"}, {"name": "Lime Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nwtb3391/nwtb3391-lime-green.webp"}, {"name": "Maroon", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/nw