  ('IntexGlobal','OCBAB101','Recession Buster Non-Woven Tote Bag','recession-buster-non-woven-tote-bag-ocbab101','Bags','Tote Bags','The Recession Buster Non-Woven Tote Bag is a budget-friendly and highly practical promotional item, perfect for everyday use, events, and branding campaigns.',250,true,false,'["Durable 80gsm Non-Woven Material: Lightweight yet sturdy for carrying essentials with ease.", "Compact & Spacious Design: Measures 21cm x 25cm with an 11cm gusset for extra storage capacity.", "Popular Size & Multi-Color Options: Available in a variety of colors to match your branding needs.", "Eco-Friendly & Reusable: A sustainable alternative to plastic bags, promoting environmental responsibility.", "Large Branding Area: Ideal for showcasing logos, slogans, or promotional messages for maximum visibility."]'::jsonb,'[{"name": "Size", "value": "21 (w) x 25 (h) with 11 cm gussets"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbab101/ocbab101-black.webp"}, {"name": "Bottle Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbab101/ocbab101-bottle-green.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbab101/ocbab101-green.webp"}, {"name": "Hot Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbab101/ocbab101-hot-pink.webp"}, {"name": "Lime Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbab101/ocbab101-lime-green.webp"}, {"name": "Maroon", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbab101/ocbab101-maroon.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d