  ('IntexGlobal','OCBAB112','1 Bottle White Kraft Paper Wine Tote Wine Carrier','1-bottle-white-kraft-paper-wine-tote-wine-carrier-ocbab112','Bags','Wine Carriers','The 1 Bottle White Kraft Paper Wine Tote is a strong and stylish packaging solution designed for gifting, retail, and promotional use. Made from 128gsm white kraft paper, this bag offers durability and a clean, premium look, with twisted paper handles for easy carrying.',250,true,false,'["Premium 128gsm White Kraft Paper: Sturdy and elegant for secure wine bottle transport.", "Fits One Standard Wine Bottle: Perfect for gifting, retail packaging, and special events.", "Twisted Paper Handles: Reinforced for durability and comfortable carrying.", "Clean & Professional Look: White kraft paper finish enhances presentation.", "Large Branding Area: Ideal for custom branding with logos and promotional messages."]'::jsonb,'[{"name": "Size", "value": "14 (w) x 32 (h) with 8 cm gussets"}]'::jsonb,'[{"name": "Main", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbab112/ocbab112-main-png.webp"}]'::jsonb,null,'supplier',true,true,0.26,28,'indent_sea','Intex','https://www.intexglobal.com/product/1-bottle-white-kraft-paper-wine-tote/');
