  ('IntexGlobal','OCBB01','Levin Tote Bag','levin-tote-bag-ocbb01','Bags','Tote Bags','The Levin Tote Bag is a budget-friendly and eco-conscious promotional bag, perfect for trade shows, retail stores, and everyday use. Its compact design and durable material make it a great choice for carrying essentials while showcasing your brand.',250,true,false,'["Durable 80gsm Non-Woven Material: Lightweight yet strong for everyday use.", "Compact Size: Measures 29cm x 34cm, ideal for carrying small essentials.", "Eco-Friendly & Reusable: A sustainable alternative to plastic bags, promoting green initiatives.", "Large Branding Area: Perfect for screen printing logos, slogans, or promotional messages.", "Versatile Use: Ideal for corporate events, trade shows, retail promotions, and giveaways."]'::jsonb,'[{"name": "Size", "value": "29 (w) x 34 (h) cm"}, {"name": "Short Handles", "value": "Designed for comfortable hand-carrying."}]'::jsonb,'[{"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb01/ocbb01-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb01/ocbb01-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb01/ocbb01-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb01/ocbb01-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb01/ocbb01-white.webp"}]'::jsonb,null,'supplier',true,true,0.87,28,'indent_sea','Intex','https://www.intexglobal.com/product/levin-tote-bag/');
