  ('IntexGlobal','OCBB11','Renwick Boutiquer Bag','renwick-boutiquer-bag-ocbb11','Bags','Tote Bags','The Renwick Boutique Bag is a premium 80gsm non-woven tote, designed for durability and maximum brand exposure. With its larger size and gusset, this bag is ideal for retail stores, trade shows, corporate events, and promotional giveaways.',250,true,false,'["Durable 80gsm Non-Woven Material: Lightweight yet sturdy, perfect for everyday use.", "Spacious Design: Measures 41cm x 36cm with a 10cm gusset, offering ample space for shopping or event materials.", "Longer Handles: Comfortable for carrying over the shoulder, enhancing convenience.", "Eco-Friendly & Reusable: A sustainable alternative to plastic bags, promoting green initiatives.", "Large Branding Area: Ideal for printing logos, slogans, or promotional messages.", "Versatile Use: Perfect for boutiques, corporate giveaways, retail promotions, and events."]'::jsonb,'[{"name": "Size", "value": "42 (w) x 36 (h) x 10 (d) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-black.webp"}, {"name": "Bottle Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-bottle-green.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-green.webp"}, {"name": "Hot Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-hot-pink.webp"}, {"name": "Lime Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-lime-green.webp"}, {"name": "Maroon", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-maroohn.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbb11/ocbb11-yellow.webp"}]'::jsonb,null,'supplier',true,true,0.98,28,'indent_sea','Intex','https://www.intexglobal.com/product/renwick-boutiquer-bag/');
