  ('IntexGlobal','OCBMS158','Canvas Drawstring Wine Gift Bag Wine Carrier','canvas-drawstring-wine-gift-bag-wine-carrier-ocbms158','Bags','Wine Carriers','The Canvas Drawstring Wine Gift Bag is a stylish and sustainable way to present and transport wine bottles, making it an excellent promotional or gifting option. Crafted from 280gsm unbleached canvas, this bag offers a premium, reusable alternative to disposable wine packaging.',250,true,false,'["Durable 280gsm Unbleached Canvas: Strong and eco-friendly, designed for long-term use.", "Natural Coloured Drawstrings: Provides a secure closure while adding a rustic, elegant touch.", "Fits One Standard Wine Bottle: Perfect for gifting, retail packaging, or event giveaways.", "Eco-Friendly & Reusable: Encourages sustainability by replacing single-use gift packaging.", "Customizable Branding Area: Ideal for screen printing logos, event details, or promotional designs."]'::jsonb,'[{"name": "Size", "value": "16 (w) x 33 (h) cm"}]'::jsonb,'[{"name": "Natural", "hex": "#E8DCC4", "image": ""}, {"name": "Black", "hex": "#000000", "image": ""}, {"name": "Royal", "hex": "#0033A0", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}]'::jsonb,null,'supplier',true,true,2.52,28,'indent_sea','Intex','https://www.intexglobal.com/product/canvas-drawstring-wine-gift-bag/');
