  ('IntexGlobal','OCBSB104','The Overnight Duffel Bag','the-overnight-duffel-bag-ocbsb104','Bags','Tote Bags','The Overnight Duffel Bag is a premium-quality 380gsm cotton canvas bag with 20L Capacity, designed for durability and convenience. Perfect for short trips, gym sessions, or promotional giveaways, this bag combines functionality with eco-friendly appeal.',250,true,false,'["Heavy-Duty 380gsm Cotton Canvas: Strong and durable for long-lasting use.", "Detachable & Adjustable Shoulder Strap: Provides comfortable carrying options for different needs.", "Spacious Main Compartment: With 20L Capacity. Ideal for overnight stays, gym essentials, or travel necessities.", "Eco-Friendly & Reusable: A sustainable alternative to synthetic travel bags.", "Large Branding Area: Perfect for screen printing logos, slogans, or custom designs."]'::jsonb,'[{"name": "Size", "value": "23 (d) x 52 x (w) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbsb104/ocbsb104-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbsb104/ocbsb104-green.webp"}, {"name": "Navy Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbsb104/ocbsb104-navy-blue.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocbsb104/ocbsb104-red.webp"}]'::jsonb,null,'supplier',true,true,13.97,28,'indent_sea','Intex','https://www.intexglobal.com/product/the-overnight-duffel-bag/');
