  ('IntexGlobal','OCLS117','Classic Cow Bell Supporter Gear','classic-cow-bell-supporter-gear-ocls117','Outdoor & Lifestyle','Supporter Gear','The Classic Cow Bell is a high-quality, attention-grabbing promotional item, ideal for sporting events, rallies, celebrations, and corporate giveaways. With a sturdy design and loud, clear sound, this cowbell is perfect for cheering on teams, creating excitement, and boosting brand visibility.',250,true,false,'["Durable Construction: Built for long-lasting use at events and celebrations.", "Loud & Clear Sound: Ensures maximum engagement at sporting games, races, and rallies.", "Classic & Compact Design: Easy to carry and use.", "Great for Promotional Activities: Ideal for team spirit, awareness campaigns, and corporate branding.", "Custom Branding Available: Can be personalized with logos or designs for promotional use."]'::jsonb,'[{"name": "Size", "value": "7.5cm W x 7cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocls117/ocls117-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocls117/ocls117-blue.webp"}, {"name": "Brown", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocls117/ocls117-brown.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocls117/ocls117-green.webp"}, {"name": "Lime Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocls117/ocls117-lime-green.webp"}, {"name": "Maroon", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ocls117/ocls117-maroon.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d3