  ('IntexGlobal','OH2080','Metal Keyring With Bottle Opener','metal-keyring-with-bottle-opener-oh2080','Key Rings','Novelty Keyrings','The Metal Keyring with Bottle Opener is a sleek and functional accessory, combining convenience with durability. Designed for everyday use, this compact and lightweight keyring ensures you always have a bottle opener on hand, making it an ideal promotional giveaway for bars, events, corporate branding, and outdoor activities.',250,true,false,'["Premium Metal Construction: Strong and durable for long-lasting use.", "Dual-Function Design: Works as both a keyring and a bottle opener.", "Compact & Portable: Easily attaches to keychains, bags, or lanyards.", "Sleek & Stylish Finish: A modern look that adds a touch of elegance.", "Perfect for On-the-Go Use: Great for picnics, parties, and travel."]'::jsonb,'[{"name": "Size", "value": "3.5cm W x 9.5cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh2080/oh2080-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh2080/oh2080-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh2080/oh2080-green.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh2080/oh2080-red.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh2080/oh2080-navy.webp"}]'::jsonb,null,'supplier',true,true,0.62,28,'indent_sea','Intex','https://www.intexglobal.com/product/metal-keyring-with-bottle-opener/');
