  ('IntexGlobal','OH9752','Journey Luggage Tag Travel Accessory','journey-luggage-tag-travel-accessory-oh9752','Travel','Travel Accessories','The Journey Luggage Tag is a practical and stylish travel accessory, designed to help travelers easily identify their luggage while showcasing your brand. Made from durable vinyl material, this tag features a strong PVC spaghetti strap attachment, ensuring a secure fit on suitcases, backpacks, and travel bags.',250,true,false,'["Durable Vinyl Material: Long-lasting and resistant to wear.", "PVC Spaghetti Strap Attachment: Provides a secure and flexible fit.", "Lightweight & Travel-Friendly: Ideal for frequent travelers.", "Window for Contact Information: Keeps personal details protected yet accessible.", "Perfect for Suitcases, Backpacks & Travel Bags: Helps with easy luggage identification."]'::jsonb,'[{"name": "Size", "value": "11.5cm W x 7cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh9752/oh9752-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh9752/oh9752-blue.webp"}, {"name": "Clear", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh9752/oh9752-clear.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh9752/oh9752-green.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/oh9752/oh9752-red.webp"}]'::jsonb,null,'supplier',true,true,1.19,28,'indent_sea','Intex','https://www.intexglobal.com/product/journey-luggage-tag/');
