  ('IntexGlobal','PS1003','Kingsford Plastic Pen','kingsford-plastic-pen-ps1003','Pens','Plastic Pens','Introducing the Kingsford Pen, a sleek and stylish writing tool designed for comfort and durability. Featuring a solid white barrel, accented with a vibrant colored rubber grip and silver trim, this pen is perfect for both professional and everyday use.',100,true,false,'["Durable Plastic Construction: Lightweight yet sturdy for long-lasting use.", "Solid White Barrel: Offers a clean and classic look, suitable for branding or personal use.", "Comfortable Rubber Grip: Available in vibrant colors, providing a secure and comfortable hold during extended writing sessions.", "Elegant Silver Trim: Adds a touch of sophistication to the pen''s design.", "Ideal Dimensions: Compact size of 14.5cm x 1cm, perfect for pockets, bags, or desk drawers."]'::jsonb,'[{"name": "Size", "value": "14.5cm X 1cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1003/ps1003-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1003/ps1003-blue.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1003/ps1003-orange.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1003/ps1003-red.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/kingsford/');
