  ('IntexGlobal','PS1008','Origin Plastic Pen','origin-plastic-pen-ps1008','Pens','Plastic Pens','The Origin Pen may be a classic push/click design, but it transforms into an unforgettable promotional product with the addition of your branding. Perfect for everyday use, this pen is both practical and impactful.',100,true,false,'["Push/Click Mechanism: A reliable and user-friendly design for smooth operation.", "Customizable Branding: Ideal for pad printing or digital printing, making your logo or message stand out.", "Versatile Appeal: A timeless and practical gift suitable for any audience or event.", "Affordable and Effective: A cost-efficient option for promoting your brand with a professional touch."]'::jsonb,'[{"name": "Size", "value": "14cm X 1cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1008/ps1008-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1008/ps1008-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1008/ps1008-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1008/ps1008-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1008/ps1008-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1008/ps1008-red.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/origin/');
