  ('IntexGlobal','PS1103','Governor Metal Pen','governor-metal-pen-ps1103','Pens','Metal Pens','Introducing the Governor Pen, an eye-catching writing instrument designed for those who appreciate quality and sophistication. With its shiny colored body and full silver trim, this aluminium pen exudes professionalism and charm.',100,true,false,'["Premium Aluminium Construction: Durable and lightweight, offering a premium feel.", "Shiny Colored Body: Available in a range of vibrant colors that enhance its sleek design.", "Push/Click Mechanism: Smooth and reliable for seamless writing.", "Full Silver Trim: Adds a polished and sophisticated touch to the overall design."]'::jsonb,'[{"name": "Size", "value": "14cm x 1cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1103/ps1103-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1103/ps1103-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1103/ps1103-green.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1103/ps1103-pink.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1103/ps1103-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1103/ps1103-red.webp"}, {"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1103/ps1103-silver.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/governor/');
