  ('IntexGlobal','PS1112','Wave Metal Pen','wave-metal-pen-ps1112','Pens','Metal Pens','Introducing the Wave Pen, a premium writing instrument that combines modern design with practicality. Made from durable aluminium and enhanced with chrome trimming, this pen is perfect for professionals and everyday use.',100,true,false,'["Durable Aluminium Body: Lightweight yet sturdy for long-lasting performance.", "Elegant Chrome Trimming: Adds a touch of sophistication to the sleek design.", "Click Action Mechanism: Smooth and reliable operation for effortless writing.", "Ergonomic Design: Comfortable to hold, making it ideal for extended writing sessions."]'::jsonb,'[{"name": "Size", "value": "14cm X 1.5cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1112/ps1112-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1112/ps1112-blue.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1112/ps1112-red.webp"}, {"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1112/ps1112-silver.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1112/ps1112-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/wave/');
