  ('IntexGlobal','PS1157','Spyder Metal Pen','spyder-metal-pen-ps1157','Pens','Metal Pens','Introducing the Spyder Ballpen, a premium writing instrument designed for those who value sophistication and functionality. Its metal construction, combined with thoughtful design details, makes it an excellent choice for personal use or corporate gifting.',100,true,false,'["Metal Construction: Durable and stylish, ensuring long-lasting performance and a premium feel.", "Twist Action Mechanism: Provides smooth and effortless operation for quick, reliable use.", "Elegant Chrome Clip: Adds a touch of shine and functionality, perfect for attaching to notebooks or pockets.", "Sophisticated Black Trim: Complements the pen''s overall design with understated elegance.", "Black Ink with Cross Refill Compatibility: Offers high-quality writing and the convenience of refillable functionality."]'::jsonb,'[{"name": "Size", "value": "14cm X 1.5cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1157/ps1157-black.webp"}, {"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1157/ps1157-silver.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1157/ps1157-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/spyder/');
