  ('IntexGlobal','PS1601','Recycled Cardboard Pen Pouch Pen Presentation','recycled-cardboard-pen-pouch-pen-presentation-ps1601','Pens','Pen Presentation','Introducing the Recycled Cardboard Pen Pouch, the perfect eco-conscious packaging solution for your promotional pens. Made from recycled cardboard, this pouch offers a sustainable way to present pens or other small stationery items while helping reduce environmental impact. Ideal for businesses looking to promote both their brand and environmental responsibility.',100,true,false,'["Eco-Friendly Material: Crafted from 100% recycled cardboard, making it an environmentally responsible choice.", "Simple and Practical Design: Provides a secure and protective packaging for pens, ensuring they are organized and ready for distribution.", "Great Promotional Product: Ideal for giveaways, corporate events, or trade shows, providing a green solution for packaging your pens."]'::jsonb,'[{"name": "Size", "value": "15cm W x 3.5cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1601/ps1601-black.webp"}, {"name": "Brown", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps1601/ps1601-brown.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/recycled-cardboard-pen-pouch/');
