  ('IntexGlobal','PS2006','750Ml Aluminium Water Bottle With Straw','750ml-aluminium-water-bottle-with-straw-ps2006','Drinkware','Drink Bottles','Quench your thirst on the move with our 750ml Aluminium Water Bottle, designed for convenience, durability, and eco-conscious living. Perfect for workouts, commutes, or outdoor adventures, this sleek bottle ensures effortless hydration wherever you go.',50,true,false,'["Built-in Straw: Enjoy easy, mess-free sipping on the go.", "Durable Aluminium Design: Lightweight yet robust for everyday use.", "Eco-Friendly & Reusable: A sustainable alternative to single-use plastics.", "Secure Lid with Portable Handle: Designed for spill-free use and easy carrying.", "Generous 750ml Capacity: Stay hydrated throughout your day.", "Care Instructions: 1. Not suitable for dishwasher use. 2. Hand washing recommended to maintain quality and longevity."]'::jsonb,'[{"name": "Size", "value": "7.2cm(dia) x 25.5cm(h)"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps2006/ps2006-black.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps2006/ps2006-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps2006/ps2006-royal.webp"}, {"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps2006/ps2006-silver.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps2006/ps2006-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/750ml-aluminium-water-bottle-with-straw/');
