  ('IntexGlobal','PS2232','350Ml Double Wall Glass Cup With Bamboo Lid','350ml-double-wall-glass-cup-with-bamboo-lid-ps2232','Drinkware','Coffee Cups','Introducing 350ml Double Wall Glass Cup with Bamboo Lid, perfect for those who value both aesthetics and functionality in their drinkware.',50,true,false,'["350ml Capacity: Ideal for your favorite hot or cold beverages, offering the perfect portion every time.", "Double-Walled Borosilicate Glass: Provides excellent insulation to keep your drink at the desired temperature while keeping the exterior comfortable to hold.", "Eco-Friendly Bamboo Lid: Adds a natural, sophisticated touch and helps retain heat or prevent spills.", "Sleek Design: A modern and minimalist look that complements any setting, whether at home or on the go.", "Not Dishwasher Safe: Hand washing is recommended to maintain the quality and longevity of the cup and lid."]'::jsonb,'[{"name": "Size", "value": "11.5 x 9.2(Dia) cm"}]'::jsonb,'[{"name": "Default", "hex": "", "image": ""}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/350ml-double-wall-glass-cup-with-bamboo-lid/');
