  ('IntexGlobal','PS3101','Silicone Wrist Band Wristband','silicone-wrist-band-wristband-ps3101','Promotional Giveaways','Wristbands','The Silicone Wrist Band is the perfect accessory for events, promotions, or everyday wear, combining style, durability, and functionality.',250,true,false,'["High-Quality Silicone: Made from durable, flexible material for comfort and long-lasting use.", "Waterproof and Sweat-Resistant: Ideal for sports, outdoor activities, or daily wear.", "Available in Vibrant Colors: Choose from a wide range of colors including black, blue, green, orange, pink, purple, red, white, and yellow.", "One Size Fits All: Designed to be comfortable and suitable for all ages.", "Customizable Surface: Perfect for adding logos, slogans, or designs, making it an excellent promotional item."]'::jsonb,'[{"name": "Size", "value": "20cm L x 1cm W"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3101/ps3101-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3101/ps3101-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3101/ps3101-orange.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3101/ps3101-pink.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3101/ps3101-red.webp"}, {"name": "Royal Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3101/ps3101-royal-blue.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3101/ps3101-white.webp"}, {"name"