  ('IntexGlobal','PS3304','Nylon Foldable Flyer Outdoor Toy','nylon-foldable-flyer-outdoor-toy-ps3304','Toys & Games','Outdoor Toys','The Nylon Foldable Flyer is a lightweight and portable accessory, perfect for outdoor activities, events, or promotional giveaways.',250,true,false,'["Durable Nylon Material: Made from strong and flexible nylon, ensuring long-lasting use.", "Foldable Design: Easily folds into a compact size, making it convenient to carry in bags or pockets.", "Wide Range of Colours: Available in various vibrant colours to suit your branding or style.", "Great for Outdoor Fun: Ideal for parks, beaches, or events, offering entertainment for all ages.", "Customizable Surface: Perfect for adding logos or designs to make a standout promotional item."]'::jsonb,'[{"name": "Size", "value": "25cm Diameter"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3304/ps3304-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3304/ps3304-green.webp"}, {"name": "Navy Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3304/ps3304-navy-blue.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3304/ps3304-orange.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3304/ps3304-red.webp"}, {"name": "Royal Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3304/ps3304-royal-blue.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3304/ps3304-white.webp"}, {"name": "Yellow", "hex": "", "imag