  ('IntexGlobal','PS4010','Ohio Tote Bag','ohio-tote-bag-ps4010','Bags','Tote Bags','The Ohio Tote Bag is a slim and practical solution, perfect for carrying textbooks, documents, or light groceries. Its sleek design and customizable options make it an excellent choice for daily use and promotional branding.',100,true,false,'["Durable Construction: Made from 80gsm non-woven polypropylene for lightweight yet sturdy performance.", "Compact and Versatile: Measures 28cm x 32cm x 10cm, ideal for textbooks, documents, or small grocery trips.", "Customizable Design: Add your 17cm x 17cm image to create a unique and impactful impression.", "Stylish Color Options: Available in Black, Navy, Red, Royal, and White to match your style or branding needs.", "Everyday Convenience: The slim, portable design is perfect for students, professionals, or casual shoppers."]'::jsonb,'[{"name": "Size", "value": "28cm x 32cm x 10cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4010/ps4010-black.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4010/ps4010-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4010/ps4010-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4010/ps4010-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4010/ps4010-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/ohio-tote-bag/');
