  ('IntexGlobal','PS4011','Hollywood Boutique Tote Bag','hollywood-boutique-tote-bag-ps4011','Bags','Tote Bags','The Hollywood Boutique Bag is designed for both style and practicality, offering a large capacity to carry your essentials with ease. With its durable non-woven design and comfortable long handles, this bag is the perfect choice for shopping, events, and daily use.',100,true,false,'["Generous Size: Measures 40cm x 32cm x 12cm, providing ample space for your belongings.", "Non-Woven Material: Built to withstand daily use while remaining lightweight and easy to carry.", "Comfortable Long Handles: Perfect for carrying the bag over your shoulder or by hand.", "Customizable Branding Area: Personalize with a 25cm x 18cm image for a unique impression that represents your brand or style.", "Color Options: Available in Black, Navy, Red, Royal, and White to suit your preferences."]'::jsonb,'[{"name": "Size", "value": "40cm x 32cm x 12cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4011/ps4011-black.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4011/ps4011-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4011/ps4011-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4011/ps4011-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4011/ps4011-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/hollywood-boutique-tote-bag/');
