  ('IntexGlobal','PS4012','Texas Conference Bag','texas-conference-bag-ps4012','Bags','Tote Bags','The Texas Conference Bag is a versatile, spacious, and durable tote designed for various uses—from grocery shopping to carrying promotional materials at events. Its non-woven Polypropylene construction and customizable branding space make it the perfect choice for marketing and daily use.',100,true,false,'["Durable Construction: Made from 80gsm non-woven Polypropylene for reliable strength and lightweight portability.", "Generous Size: Measures 38cm x 42cm with a 9cm V gusset, offering ample space for groceries, documents, or event essentials.", "Secure Handle: The sturdy handle provides a comfortable and reliable grip for easy carrying.", "Custom Branding Area: Add your 25cm x 25cm image to personalize the bag for a unique and lasting impression.", "Color Options: Available in Black, Navy, Red, Royal, and White to match your branding or style."]'::jsonb,'[{"name": "Size", "value": "38cm x 42cm x 9cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4012/ps4012-black.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4012/ps4012-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4012/ps4012-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4012/ps4012-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4012/ps4012-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/texas-conference-bag/');
