  ('IntexGlobal','PS5010','Tiger Usb Flash Drive','tiger-usb-flash-drive-ps5010','Tech','USB Flash Drives','The Tiger USB Flash Drive is a stylish and functional storage solution, ideal for personal use, corporate gifting, or promotional giveaways.',1,true,false,'["Swivel Design: Features a durable metal swivel that protects the USB connector when not in use, combining functionality with style.", "Customizable Plastic Casing: The casing can be PMS matched to align with your brand or design preferences.", "Printing Options: Offers single-color, full-color, and epoxy dome printing on the metal swivel for vibrant and lasting customization.", "Portable and Compact: Lightweight and easy to carry, perfect for storing and transferring files on the go.", "Versatile Applications: Ideal for office, school, or home use, as well as promotional events."]'::jsonb,'[{"name": "Size", "value": "5.5cm W x 2cm H x 0.9cm D"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5010/ps5010-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5010/ps5010-blue.webp"}, {"name": "Light Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5010/ps5010-light-green.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5010/ps5010-pink.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5010/ps5010-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5010/ps5010-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/pro