  ('IntexGlobal','PS5051','Acrylic Beanie Hat Beany','acrylic-beanie-hat-beany-ps5051','Headwear','Beanies','Introducing Acrylic Beanie Hat, designed for both style and practicality. Crafted from 100% high-quality acrylic, this beanie offers exceptional breathability and waterproof properties, ensuring comfort and protection in any weather.',250,true,false,'["Premium Acrylic Material: Breathable, durable, and water-resistant for all-day comfort and protection.", "Sophisticated Dobby Style: Adds a stylish, textured design for a modern and sophisticated look.", "Unisex Fit: A versatile and comfortable design suitable for both men and women.", "Customizable: Perfect for adding your logo or branding, with a variety of colors to choose from.", "Versatile: Ideal for various activities, whether you''re skiing, hiking, or running errands."]'::jsonb,'[{"name": "Size", "value": "Adult"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5051/ps5051-black.webp"}, {"name": "Gold", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5051/ps5051-gold.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5051/ps5051-green.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5051/ps5051-grey.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5051/ps5051-navy.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5051/ps5051-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5051/ps5051-red.we