  ('IntexGlobal','PS5054','Winter Fleece Beanie Hat Beany','winter-fleece-beanie-hat-beany-ps5054','Headwear','Beanies','Introducing our Winter Fleece Beanie Hat, the ultimate cold-weather essential designed to keep you warm and stylish all season long.',250,true,false,'["Premium Material: Made from 100% acrylic with a soft fleece lining for exceptional warmth and comfort.", "Cozy Insulation: The fleece interior traps heat, ensuring you stay warm even in the coldest weather.", "Durable Knitted Construction: Provides a snug fit and long-lasting wear.", "Unisex Design: A versatile style that suits all adults, regardless of gender.", "Customizable: Personalize with your logo or design to add a unique touch to your winter wardrobe."]'::jsonb,'[{"name": "Size", "value": "Adult"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5054/ps5054-black.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5054/ps5054-grey.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5054/ps5054-navy.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5054/ps5054-white.webp"}]'::jsonb,null,'supplier',true,true,3.0,28,'indent_sea','Intex','https://www.intexglobal.com/product/winter-fleece-beanie-hat/');
