  ('IntexGlobal','PS60051','Dye Sublimated Lanyard With Swivel Clip 15mm','dye-sublimated-lanyard-with-swivel-clip-15mm-ps60051','Promotional Giveaways','Lanyards','The Dye Sublimated Lanyard is a stylish and practical solution for carrying ID cards, passes, or keys, offering full-colour customization and durable functionality.',1,true,false,'["Full-Colour Sublimation: High-quality dye sublimation allows vibrant, all-over custom designs to showcase your brand or message.", "Durable Polyester Material: Made from strong and comfortable polyester for extended wear.", "Compact Size: Measures 15mm wide and 900mm long, perfect for everyday use.", "Swivel Clip: Securely holds ID badges, passes, or keys for convenience.", "Safety Breakaway (Optional): Can be equipped with a breakaway feature for added safety upon request."]'::jsonb,'[{"name": "Size", "value": "90 (w) x 15(h) cm"}]'::jsonb,'[{"name": "Custom", "hex": "", "image": ""}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/dye-sublimated-lanyard-with-swivel-clip-15mm/');
