  ('IntexGlobal','PS7001','A5 Notebook','a5-notebook-ps7001','Office & Desk','Notebooks','The A5 Notebook is the perfect companion for work, school, or personal use, offering practicality with a sleek design.',100,true,false,'["A5 Size: Compact and portable, making it ideal for everyday use or travel.", "Hard Cover: Provides durability and protection, ensuring your notes stay secure.", "Made with recycled paper for an environmentally friendly choice.", "160 Lined Pages: Ample space for writing, planning, or organizing ideas.", "Matching Bookmark Ribbon: Keep your place easily with a stylish ribbon in a coordinating colour.", "Elastic Closure: Ensures the notebook stays closed and secure when not in use."]'::jsonb,'[{"name": "Size", "value": "20.4cm x 14.3cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7001/ps7001-black.webp"}, {"name": "Light Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7001/ps7001-light-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7001/ps7001-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7001/ps7001-orange.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7001/ps7001-pink.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7001/ps7001-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7001/ps7001-red.webp"}, {"name": "Sky Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/supp