  ('IntexGlobal','PS7009','RPET Notebook','rpet-notebook-ps7009','Office & Desk','Notebooks','The RPET Notebook is an eco-conscious choice that combines practicality with sustainability, perfect for professionals, students, or promotional events.',100,true,true,'["Eco-Friendly RPET Cover: Made from recycled PET materials, contributing to a more sustainable future.", "Made with recycled paper for an environmentally friendly choice.", "A5 Size: Compact and portable, ideal for daily use at work, school, or on the go.", "Available in 4 Classic Colours: Choose from a range of timeless colours to suit your style or branding.", "Customizable Surface: Suitable for full-colour transfer, making it an excellent choice for branding or personalization."]'::jsonb,'[{"name": "Size", "value": "21cm x 14.5cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7009/ps7009-black.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7009/ps7009-grey.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7009/ps7009-navy.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7009/ps7009-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/rpet-notebook/');
