  ('IntexGlobal','PS7105','Clear Pvc Pencil Case','clear-pvc-pencil-case-ps7105','Office & Desk','Pencil Cases','Introducing the Clear PVC Pencil Case, perfect for students, professionals, and travelers alike. This case combines practicality with simplicity.',250,true,false,'["Transparent Design: The clear PVC material allows you to easily see and locate your items at a glance.", "Secure Zip Closure: Equipped with a sturdy zipper to keep your belongings safe and organized.", "Spacious Dimensions: Measuring 22cm x 14cm, it provides ample room for pens, pencils, stationery, or small personal items.", "Durable and Easy to Clean: Made from high-quality PVC, ensuring long-lasting use and effortless maintenance."]'::jsonb,'[{"name": "Size", "value": "22cm x 14cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7105/ps7105-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7105/ps7105-green.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7105/ps7105-pink.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7105/ps7105-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7105/ps7105-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7105/ps7105-royal.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7105/ps7105-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/pro