  ('IntexGlobal','PS8121','Neoprene Wine Bottle Holder Cooler Bag','neoprene-wine-bottle-holder-cooler-bag-ps8121','Bags','Cooler Bags','The Neoprene Wine Bottle Holder is the perfect accessory for transporting wine with care and elegance, ideal for gatherings, picnics, or gifting.',250,true,false,'["Insulated Neoprene Material: Keeps your wine bottles at the desired temperature, regardless of the weather.", "Reinforced Stitching: Sturdy stitching around the handles and opening provides durability and secure handling.", "Easy Transport: Ergonomic handles make carrying single wine bottles convenient and safe.", "Customizable Surface: Personalize with your image or design for a unique and memorable impression.", "Versatile Use: Perfect for parties, picnics, or as a thoughtful and stylish gift."]'::jsonb,'[{"name": "Size", "value": "15.2cm W x 37.5cm H"}]'::jsonb,'[{"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8121/ps8121-white.webp"}]'::jsonb,null,'supplier',true,true,3.52,28,'indent_sea','Intex','https://www.intexglobal.com/product/neoprene-wine-bottle-holder-2/');
