  ('IntexGlobal','PS8312','Brighton Metal Keyring Bottle Opener','brighton-metal-keyring-bottle-opener-ps8312','Key Rings','Novelty Keyrings','Introducing the Brighton Metal Keyring Bottle Opener – a sleek and functional accessory that combines durability with convenience, designed to complement your branding needs. Perfect for everyday use or as a stylish promotional item.',100,true,false,'["Heavy-Duty Design: Built to last, this sturdy bottle opener easily handles tough caps with ease.", "Ring Tab Pull: Includes a convenient ring tab for effortless opening.", "Compact and Portable: Easily attaches to your keys, making it perfect for on-the-go use.", "Customizable for Branding: Ideal for engraving or printing your logo, ensuring maximum brand visibility."]'::jsonb,'[{"name": "Size", "value": "2cm W x 9cm H"}]'::jsonb,'[{"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8312/ps8312-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/brighton-metal-keyring-bottle-opener/');
