  ('IntexGlobal','PS8511','Coogee Gym Cotton Towel Large','coogee-gym-cotton-towel-large-ps8511','Outdoor & Lifestyle','Towels','Introducing the Coogee Gym Cotton Towel Large, designed for both comfort and performance. Made from soft, high-quality 400gsm cotton with a durable polyester band, this towel is perfect for your gym sessions or any fitness activity.',100,true,false,'["Premium 400gsm Cotton: Crafted from high-quality cotton, offering a soft, absorbent surface to keep you dry and comfortable.", "Durable Polyester Band: Features a polyester band for added strength and style, ensuring durability during intense workouts.", "Perfect Size: Measures 30 x 110 cm, providing ample coverage for wiping away sweat or drying off after a workout.", "Stylish Strip Design: The strip measures 8cm x 29cm, adding a touch of modern design to your workout gear.", "Pet-Friendly Option: Ideal for use as a towel for pets, offering comfort and absorbency for grooming or bath time."]'::jsonb,'[{"name": "Size", "value": "30 x 100cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8511/ps8511-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8511/ps8511-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8511/ps8511-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8511/ps8511-red.webp"}, {"name": "Royal Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8511/ps8511-royal-blue.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8511/ps8511-white.webp"}, 