  ('IntexGlobal','PS9120','Rain Poncho Grooming','rain-poncho-grooming-ps9120','Personal Care','Grooming','Introducing the Transparent White Disposable Rain Poncho, this poncho offers quick protection against rain while showcasing your brand with vibrant customization options.',100,true,false,'["Transparent White Design: Sleek and versatile, perfect for any outdoor event or activity.", "Compact Packaging: Comes in a convenient zip lock bag for easy carrying and storage.", "Full-Colour Digital Label: Customizable with a vibrant full-colour label to promote your brand or message.", "Poncho Size: 101 x 101 cm, providing ample coverage for most adults.", "Disposable & Lightweight: A practical, one-time-use solution for staying dry on the go."]'::jsonb,'[{"name": "Size", "value": "101 x 101 cm"}]'::jsonb,'[{"name": "Clear", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9120/ps9120-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/rain-poncho/');
