  ('IntexGlobal','PS9212','Bamboo Nail File Novelty Giveaway','bamboo-nail-file-novelty-giveaway-ps9212','Promotional Giveaways','Novelty Giveaways','Introducing the Bamboo Nail File – a sustainable and practical grooming accessory designed for everyday use with a touch of eco-friendly elegance.',100,true,false,'["Eco-Friendly Material: Made from natural bamboo, offering a sustainable alternative to plastic nail files.", "Black Emery Board: Features a coarse filing surface for effective and precise nail shaping.", "Compact and Handy: Perfect for travel, handbags, or keeping in your desk for on-the-go touch-ups.", "Customizable Surface: Ideal for branding with logos or messages, making it an excellent promotional item."]'::jsonb,'[{"name": "Size", "value": "11 x 2.2 x 0.5 cm"}]'::jsonb,'[{"name": "Natural", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9212/ps9212-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/bamboo-nail-file/');
