  ('IntexGlobal','PSSAN01','Hand Sanitiser 60Ml Made In Australia','hand-sanitiser-60ml-made-in-australia-pssan01','Personal Care','Hand Sanitiser','Introducing the Hand Sanitiser 60ml – a compact, Australian-made solution for maintaining hygiene and safety on the go.',100,true,false,'["Made in Australia: Locally produced to ensure quality and support Australian manufacturing.", "Effective Formula: Contains 65% ethyl alcohol, eliminating over 99.9% of germs and bacteria.", "Compact and Portable: A convenient 60ml plastic bottle, perfect for travel, work, or everyday use.", "Hygienic and Reliable: Designed to provide quick and effective hand sanitization wherever you are."]'::jsonb,'[{"name": "Size", "value": "4.8cm W x 9cm H"}]'::jsonb,'[{"name": "Clear", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/pssan01/pssan01-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/?post_type=product&p=5125');
