  ('IntexGlobal','PSSUN01','30Ml Spf50 Sunscreen Lotion','30ml-spf50-sunscreen-lotion-pssun01','Personal Care','Sunscreen & Lotions','Introducing the 30ml SPF50 Sunscreen Lotion by Sunsational – your compact and reliable companion for ultimate sun protection.',100,true,false,'["SPF50+ Broad Spectrum Protection: Shields against both UVA and UVB rays, keeping your skin safe under the harsh summer sun.", "Water-Resistant Formula: Perfect for outdoor activities, providing durable protection that lasts.", "Non-Greasy and Quick-Drying: Rubs on easily, dries quickly, and leaves no greasy residue.", "Cosmetic-Friendly: Free from titanium dioxide and zinc oxide, making it suitable for use under makeup.", "Portable Size: The 30ml bottle is perfect for travel, handbags, or pocket use."]'::jsonb,'[{"name": "Size", "value": "4 cm (w) x 8 cm (h)"}]'::jsonb,'[{"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/pssun01/pssun01-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/30ml-spf50-sunscreen-lotion/');
