  ('IntexGlobal','PSSUN08','1L Spf50 Sunscreen Lotion','1l-spf50-sunscreen-lotion-pssun08','Personal Care','Sunscreen & Lotions','Introducing the 1L SPF50 Sunscreen Lotion by Sunsational – the perfect bulk solution for superior sun protection, ideal for workplaces, outdoor events, or family use.',10,true,false,'["SPF50+ Broad Spectrum Protection: Provides effective shielding against both UVA and UVB rays for maximum sun safety.", "Water-Resistant and Non-Greasy: Designed for active use with a quick-drying formula that rubs on clear and leaves no residue.", "Cosmetic-Friendly: Free from titanium dioxide and zinc oxide, making it ideal for use under makeup and cosmetics.", "Generous 1L Size: Perfect for high-usage environments such as workplaces, schools, or outdoor events."]'::jsonb,'[{"name": "Size", "value": "18cm H x 11cm W"}]'::jsonb,'[{"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/pssun08/pssun08-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/1l-spf50-sunscreen-lotion/');
