  ('IntexGlobal','STRS04','Basketball Stress Shape Stress Ball & Toy','basketball-stress-shape-stress-ball-toy-strs04','Toys & Games','Stress Balls & Toys','The Basketball Stress Shape is an engaging and stress-relieving promotional item, designed for sports fans, athletes, and corporate giveaways. Made from high-quality polyurethane foam, this basketball-shaped stress ball is soft, lightweight, and durable, making it a perfect promotional giveaway at sports events, trade shows, and marketing campaigns.',250,true,false,'["Durable Polyurethane Foam: Soft and squeezable for stress relief.", "Basketball-Shaped Design: Perfect for sports-themed branding and promotions.", "Helps Reduce Stress & Tension: Great for office workers, students, and event attendees.", "Compact & Lightweight: Easy to carry and store.", "Ideal for Sports Events & Promotions: A fun and unique way to showcase your brand."]'::jsonb,'[{"name": "Size", "value": "6 (d) cm"}]'::jsonb,'[{"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs04/strs04-main.webp"}]'::jsonb,null,'supplier',true,true,0.6,28,'indent_sea','Intex','https://www.intexglobal.com/product/basketball-stress-shape/');
