  ('IntexGlobal','UMBR10','The Dunes Golf Umbrella','the-dunes-golf-umbrella-umbr10','Outdoor & Lifestyle','Umbrellas','The Dunes Golf Umbrella combines size, strength, and style for maximum protection on and off the course. Featuring a 30-inch, 8-bone automatic frame with a 190T encrypted impact fabric canopy in a two-tone design, it offers exceptional wind resistance and UPF 50+ sun protection. Built with a fibreglass shaft, fibreglass ribs, and an EVA handle, this umbrella is both durable and comfortable to use,',250,true,false,'["30-inch 8-bone automatic frame for wide coverage.", "Two-tone 190T encrypted impact fabric canopy.", "Strong fibreglass shaft and ribs for flexibility and durability.", "EVA handle for comfortable grip.", "Extra-deep canopy for superior wind resistance and UPF 50+ sun protection."]'::jsonb,'[{"name": "Size", "value": "76 (w) cm"}]'::jsonb,'[{"name": "Black", "hex": "#000000", "image": ""}, {"name": "Blue", "hex": "#0057B8", "image": ""}, {"name": "Bottle Green & Mint", "hex": "#004225", "image": ""}, {"name": "Brown", "hex": "#795548", "image": ""}, {"name": "Coral", "hex": "#FF7F50", "image": ""}, {"name": "Crimson", "hex": "#DC143C", "image": ""}, {"name": "Firebrick", "hex": "#B22222", "image": ""}, {"name": "Gold", "hex": "#D4AF37", "image": ""}, {"name": "Green", "hex": "#009639", "image": ""}, {"name": "Green & Silver", "hex": "#009639", "image": ""}, {"name": "Grey", "hex": "#8A8D8F", "image": ""}, {"name": "Indigo", "hex": "#4B0082", "image": ""}, {"name": "Khaki", "hex": "#C3B091", "image": ""}, {"name": "Lavender", "hex": "#B57EDC", "image": ""}, {"name": "Light Pink", "hex": "#FFB6C1", "image": ""}, {"name": "Lime Green", "hex": "#A5CD39", "image": ""}, {"name": "Magenta", "hex": "#FF00FF", "image": ""}, {"name": "Maroon", "hex": "#800000", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}, {"name": "Navy & Bronze", "hex": "#001F3F", "image": ""}, {"name": "Olive", "hex": "#808000", "image": ""}, {"name": "Orange", "hex": "#FF6900", "image": ""}, {"name": "Purple", "hex": "#5F259F", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}, {"name": "Red & Gold", "hex": "#C8102E", "image": ""}, {"name": "Royal Blue", "hex": "#0033A0", "image": ""}, {"name": "Salmon", "hex": "#FA8072", "image": ""}, {"name": "Silver", "hex": "#C0C0C0", "image": ""}, {"name": "Teal", "hex": "#008080", "image": ""}, {"name": "Wheat", "hex": "#F5DEB3", "image": ""}, {"name": "White", "hex": "#FFFFFF", "image": ""}, {"name": "Yellow", "hex": "#FFD700", "image": ""}, {"name": "Yellow & Black", "hex": "#FFD700", "image": ""}]'::jsonb,null,'supplier',true,true,7.5,28,'indent_sea','Intex','https://www.intexglobal.com/product/the-dunes-golf-umbrella/');
